if input('Підтвердити? (так/ні): ').strip().lower() not in ('так','y','yes'): raise SystemExit('Скасовано')
pw=getpass.getpass('Пароль ADMIN (admin@vector.ua, друкуй вручну): ')
d,c=api('/login',method='POST',data={'email':'admin@vector.ua','password':pw}); tok=d.get('token')
print('Логін admin:', c, '| роль:', (d.get('user') or {}).get('role'), '| токен:', bool(tok))
if not tok: raise SystemExit('Логін не вдався')
s0=sorted(DATA)[0]; d0=days[0]; r0=DATA[s0][str(d0)]
_,tc=api('/protocols',tok,'PUT',{'studentId':s0,'day':d0,'absent':r0['absent'],'mScores':r0['m'],'tScores':r0['t']})
print('Тестовий запис (', s0, 'день', d0, ') код:', tc)
if tc not in (200,201): print('Не пройшло — скинь вивід Клоду.'); raise SystemExit
ok=fail=0; errs=[]
for sid in sorted(DATA):
    for day in sorted(DATA[sid], key=int):
        if int(day) not in days: continue
        r=DATA[sid][day]
        _,cc=api('/protocols',tok,'PUT',{'studentId':sid,'day':int(day),'absent':r['absent'],'mScores':r['m'],'tScores':r['t']})
        if cc in (200,201): ok+=1
        else: fail+=1; errs.append((sid,day,cc))
print('Внесено:', ok, '| помилок:', fail)
for e in errs[:10]: print('  FAIL', e)
print('Готово' if fail==0 else 'Є помилки')
